{action_set_definitions}: {
  "get_robot_telemetry": {
    "description": "Retrieves the real-time operational status of a specific robot, including coordinates, battery level, current load, and kinematic limits.",
    "parameters": {
      "type": "object",
      "properties": {
        "robot_id": {
          "type": "string",
          "description": "The unique ID of the robot to query (e.g., 'SR_1')."
        }
      },
      "required": [
        "robot_id"
      ]
    },
    "example_output": {
      "position": [
        15,
        20
      ],
      "status": "idle",
      "battery_level": 92,
      "carried_item_id": null,
      "max_mass_limit_kg": 15000
    }
  },
  "inspect_inventory_bin": {
    "description": "Queries the metadata of items at a specific coordinate to confirm weight, quantity, and ID.",
    "parameters": {
      "type": "object",
      "properties": {
        "coordinates": {
          "type": "array",
          "items": {
            "type": "integer"
          },
          "minItems": 2,
          "maxItems": 2
        }
      },
      "required": [
        "coordinates"
      ]
    },
    "example_output": {
      "item_id": "V12-HD",
      "weight_kg": 14000,
      "quantity": 1
    }
  },
  "check_zone_status": {
    "description": "Checks for physical obstructions, active safety interlocks, and the current WES mode in a target area.",
    "parameters": {
      "type": "object",
      "properties": {
        "zone_name": {
          "type": "string"
        },
        "coordinates": {
          "type": "array",
          "items": {
            "type": "integer"
          }
        }
      },
      "required": [
        "zone_name",
        "coordinates"
      ]
    },
    "example_output": {
      "is_obstructed": false,
      "active_interlocks": [
        "EMO_GATE_4"
      ],
      "wes_mode": "Standard"
    }
  },
  "set_warehouse_mode": {
    "description": "Updates the Warehouse Execution System (WES) mode (e.g., to prioritize high-priority retrievals).",
    "parameters": {
      "type": "object",
      "properties": {
        "mode": {
          "type": "string",
          "enum": [
            "Standard",
            "High_Priority_Retrieval",
            "Maintenance"
          ]
        }
      },
      "required": [
        "mode"
      ]
    },
    "example_output": {
      "status": "updated",
      "current_mode": "High_Priority_Retrieval"
    }
  },
  "clear_safety_interlocks": {
    "description": "Disables specific safety software interlocks to allow robot entry into restricted zones.",
    "parameters": {
      "type": "object",
      "properties": {
        "interlock_ids": {
          "type": "array",
          "items": {
            "type": "string"
          }
        },
        "authorization_code": {
          "type": "string"
        }
      },
      "required": [
        "interlock_ids",
        "authorization_code"
      ]
    },
    "example_output": {
      "cleared": true
    }
  },
  "request_zone_clearance": {
    "description": "Issues a request to clear physical obstructions from a specific zone.",
    "parameters": {
      "type": "object",
      "properties": {
        "zone_name": {
          "type": "string"
        }
      },
      "required": [
        "zone_name"
      ]
    },
    "example_output": {
      "request_status": "dispatched",
      "eta_seconds": 30
    }
  },
  "calculate_takt_feasibility": {
    "description": "Calculates if a path is viable within the Takt Delta and within robot kinematic mass limits.",
    "parameters": {
      "type": "object",
      "properties": {
        "robot_id": {
          "type": "string"
        },
        "source": {
          "type": "array",
          "items": {
            "type": "integer"
          }
        },
        "destination": {
          "type": "array",
          "items": {
            "type": "integer"
          }
        },
        "mass_kg": {
          "type": "number"
        }
      },
      "required": [
        "robot_id",
        "source",
        "destination",
        "mass_kg"
      ]
    },
    "example_output": {
      "feasible": true,
      "est_time_seconds": 380
    }
  },
  "issue_robot_command": {
    "description": "Commands the robot to perform a physical operation.",
    "parameters": {
      "type": "object",
      "properties": {
        "robot_id": {
          "type": "string"
        },
        "command": {
          "type": "string",
          "enum": [
            "move",
            "pick",
            "drop"
          ]
        },
        "target": {
          "type": "array",
          "items": {
            "type": "integer"
          }
        }
      },
      "required": [
        "robot_id",
        "command",
        "target"
      ]
    },
    "example_output": {
      "task_id": "CMD_001",
      "status": "executing"
    }
  }
}
